module sr_latch (
    input wire inv_S,
    input wire R,
    output reg Q,
    output reg Qn
);
    always @(inv_S, R) begin
        if (inv_S && !R) begin
            Q <= 1;
            Qn <= 0;
        end else if (!inv_S && R) begin
            Q <= 0;
            Qn <= 1;
        end
        // State remains unchanged if both inv_S and R are low or both are high
    end
endmodule
